{
  "flashcards": [
    {
      "qfmt": "How does the wealth of the top 10 richest people compare to that of the bottom three billion people?",
      "afmt": "The top 10 richest people have more wealth than the bottom three billion people combined.",
      "markers": [
        ["00:00:02,159", "00:00:12,400"]
      ],
      "score": 8
    },
    {
      "qfmt": "What is described as the fundamental currency of life that predates money and humanity?",
      "afmt": "Energy is described as the fundamental currency of life, underlying all biological and economic systems.",
      "markers": [
        ["00:01:06,320", "00:01:14,240"]
      ],
      "score": 9
    },
    {
      "qfmt": "What biological process allows plants to capture solar energy and store it as sugar?",
      "afmt": "Photosynthesis is the process where plants use sunlight to convert carbon dioxide and water into sugar, storing solar energy for use by life.",
      "markers": [
        ["00:02:35,519", "00:02:58,319"]
      ],
      "score": 8
    },
    {
      "qfmt": "What test is used to evaluate whether profit creates new usable energy or merely transfers it within a system?",
      "afmt": "The boundary test is used, where you expand the view from individual to ecosystem to see if total usable energy increases, indicating value creation versus extraction.",
      "markers": [
        ["00:06:31,600", "00:07:48,240"]
      ],
      "score": 9
    },
    {
      "qfmt": "What paradox describes how improvements in efficiency can lead to increased consumption rather than savings?",
      "afmt": "Jevons paradox describes how technological efficiency gains often result in higher overall consumption of a resource, offsetting potential savings.",
      "markers": [
        ["00:16:57,920", "00:17:09,520"]
      ],
      "score": 7
    }
  ]
}
